import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";

export default function Navbar() {
  const location = useLocation();
  const [active, setActive] = useState(location.pathname);

  const handleClick = (path) => {
    setActive(path);
  };

  const styles = {
    navbar: {
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "14px 6%",
      background: "rgba(255, 255, 255, 0.95)",
      boxShadow: "0 3px 12px rgba(0,0,0,0.1)",
      position: "sticky",
      top: 0,
      zIndex: 1000,
      fontFamily: "Poppins, sans-serif",
      backdropFilter: "blur(8px)",
    },
    logoContainer: {
      display: "flex",
      alignItems: "center",
      gap: "10px",
    },
    logoImg: {
      width: "40px",
      height: "40px",
      borderRadius: "50%",
    },
    logoText: {
      fontSize: "1.6rem",
      fontWeight: 700,
      color: "#ff385c",
      textDecoration: "none",
    },
    navLinks: {
      display: "flex",
      gap: "45px",
    },
    navItem: (isActive) => ({
      textDecoration: "none",
      color: isActive ? "#ff385c" : "#333",
      fontSize: "1.1rem",
      fontWeight: 600,
      transition: "all 0.3s ease",
      display: "flex",
      alignItems: "center",
      gap: "6px",
    }),
  };

  return (
    <nav style={styles.navbar}>
      {/* 🌍 Left: Logo */}
      <div style={styles.logoContainer}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/888/888859.png"
          alt="Logo"
          style={styles.logoImg}
        />
        <Link to="/" style={styles.logoText}>
          StayEase
        </Link>
      </div>

      {/* 🔄 Dynamic Nav Links */}
      <div style={styles.navLinks}>
        <Link
          to="/"
          onClick={() => handleClick("/")}
          style={styles.navItem(active === "/")}
        >
          {active === "/" ? "🏠" : "🏠 Home"}
        </Link>

        <Link
          to="/experience"
          onClick={() => handleClick("/experience")}
          style={styles.navItem(active === "/experience")}
        >
          {active === "/experience" ? "🌄" : "🌄 Experience"}
        </Link>

        <Link
          to="/services"
          onClick={() => handleClick("/services")}
          style={styles.navItem(active === "/services")}
        >
          {active === "/services" ? "🛎️" : "🛎️ Services"}
        </Link>
      </div>
    </nav>
  );
}
